// ZAPIER MASTER BRIDGE — Route all external events
const body = $input.first().json;
const source = body.source || 'unknown';
const event = body.event || 'unknown';
const payload = body.payload || body;

// Route map: source.event → handler
const routes = {
  'linear.issue_created': 'slack_notify',
  'linear.issue_updated': 'slack_notify',
  'gmail.new_from_noizy': 'notion_inbox',
  'gmail.new_important': 'slack_alert',
  'calendar.recording_session': 'prep_checklist',
  'calendar.meeting': 'slack_notify',
  'github.push': 'slack_dev',
  'github.pr_created': 'slack_dev',
  'github.pr_merged': 'deploy_trigger',
  'stripe.payment': 'ledger_update',
  'stripe.subscription': 'ledger_update',
  'notion.page_updated': 'sync_linear',
  'slack.mention': 'gabriel_alert',
  'zapier.test': 'echo',
};

const handler = routes[`${source}.${event}`] || 'unknown_route';

return [{
  json: {
    source,
    event,
    handler,
    payload,
    received_at: new Date().toISOString(),
    bridge: 'ZAPIER_MASTER_BRIDGE_v1'
  }
}];

// Build Slack message from event
const { source, event, payload } = $input.first().json;
const emoji = {
  'linear': ':linear:',
  'github': ':github:',
  'gmail': ':email:',
  'calendar': ':calendar:',
  'stripe': ':money_with_wings:',
  'slack': ':speech_balloon:'
};
const icon = emoji[source] || ':zap:';
const title = payload.title || payload.subject || payload.summary || event;
const url = payload.url || payload.link || '';

return [{
  json: {
    text: `${icon} *${source.toUpperCase()}* — ${event}\n>${title}${url ? '\n' + url : ''}`,
    channel: source === 'github' ? '#dev' : '#general'
  }
}];

// Log to Notion inbox
const { source, event, payload } = $input.first().json;
return [{
  json: {
    title: `[${source}] ${event}: ${payload.title || payload.subject || 'Event'}`,
    source,
    event,
    received: new Date().toISOString()
  }
}];
